(84, 27, 'vi', 'Máy phun sương tạo ẩm không khí Poermax J14 dung tích 4L giọt sương nano tăng độ ẩm nhanh', '', '', '<p class=\"QN2lPu\" style=\"margin: 0px; color: rgba(0, 0, 0, 0.8); font-family: \'Helvetica Neue\', Helvetica, Arial, 文泉驛正黑, \'WenQuanYi Zen Hei\', \'Hiragino Sans GB\', \'儷黑 Pro\', \'LiHei Pro\', \'Heiti TC\', 微軟正黑體, \'Microsoft JhengHei UI\', \'Microsoft JhengHei\', sans-serif; font-size: 14px; white-space-collapse: preserve; background-color: #ffffff;\">CHẾ ĐỘ BẢO H&Agrave;NH POERMAX</p>\r\n<p class=\"QN2lPu\" style=\"margin: 0px; color: rgba(0, 0, 0, 0.8); font-family: \'Helvetica Neue\', Helvetica, Arial, 文泉驛正黑, \'WenQuanYi Zen Hei\', \'Hiragino Sans GB\', \'儷黑 Pro\', \'LiHei Pro\', \'Heiti TC\', 微軟正黑體, \'Microsoft JhengHei UI\', \'Microsoft JhengHei\', sans-serif; font-size: 14px; white-space-collapse: preserve; background-color: #ffffff;\">● Bảo h&agrave;nh 3 th&aacute;ng</p>\r\n<p class=\"QN2lPu\" style=\"margin: 0px; color: rgba(0, 0, 0, 0.8); font-family: \'Helvetica Neue\', Helvetica, Arial, 文泉驛正黑, \'WenQuanYi Zen Hei\', \'Hiragino Sans GB\', \'儷黑 Pro\', \'LiHei Pro\', \'Heiti TC\', 微軟正黑體, \'Microsoft JhengHei UI\', \'Microsoft JhengHei\', sans-serif; font-size: 14px; white-space-collapse: preserve; background-color: #ffffff;\">● Lỗi 1 đổi 1 trong 30 ng&agrave;y</p>\r\n<p class=\"QN2lPu\" style=\"margin: 0px; color: rgba(0, 0, 0, 0.8); font-family: \'Helvetica Neue\', Helvetica, Arial, 文泉驛正黑, \'WenQuanYi Zen Hei\', \'Hiragino Sans GB\', \'儷黑 Pro\', \'LiHei Pro\', \'Heiti TC\', 微軟正黑體, \'Microsoft JhengHei UI\', \'Microsoft JhengHei\', sans-serif; font-size: 14px; white-space-collapse: preserve; background-color: #ffffff;\">&nbsp;</p>\r\n<p class=\"QN2lPu\" style=\"margin: 0px; color: rgba(0, 0, 0, 0.8); font-family: \'Helvetica Neue\', Helvetica, Arial, 文泉驛正黑, \'WenQuanYi Zen Hei\', \'Hiragino Sans GB\', \'儷黑 Pro\', \'LiHei Pro\', \'Heiti TC\', 微軟正黑體, \'Microsoft JhengHei UI\', \'Microsoft JhengHei\', sans-serif; font-size: 14px; white-spac