(20, 'system', 'meta_description', '{\"en\":\"InnoShop is an innovative open-source e-commerce platform developed based on Laravel 11, featuring multi-language and multi-currency support. It adopts a powerful and flexible plugin architecture based on Hooks, providing users with a wealth of customization and extension capabilities. Welcome to experience InnoShop and create your own e-commerce platform!\",\"vi\":null}', 1, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(21, 'system', 'slideshow', '[{\"image\":{\"en\":\"images\\/demo\\/banner\\/banner-1-en.jpg\",\"zh-cn\":\"images\\/demo\\/banner\\/banner-1-cn.jpg\"},\"link\":\"\\/en\\/category-women-clothing\"},{\"image\":{\"en\":\"images\\/demo\\/banner\\/banner-2-en.jpg\",\"zh-cn\":\"images\\/demo\\/banner\\/banner-2-cn.jpg\"},\"link\":\"\\/en\\/category-women-clothing\"}]', 1, '2025-04-26 15:29:47', '2025-04-26 15:29:47'),
(22, 'system', 'ai_prompt_article_seo_description', '请根据关键字为该文章生成一个优化的文章SEO描述。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(23, 'system', 'ai_prompt_article_seo_keywords', '请根据关键字为该文章生成一个优化的文章SEO关键词。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(24, 'system', 'ai_prompt_article_seo_title', '请根据关键字为该文章生成一个有效的文章SEO标题。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(25, 'system', 'ai_prompt_article_slug', '请根据关键字为该文章生成一个简洁、明确的文章slug。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(26, 'system', 'ai_prompt_article_summary', '请根据关键字为该文章撰写一份简洁而引人注目的产品摘要。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(27, 'system', 'ai_prompt_product_selling_point', '请为该商品生成一份简洁有力的产品卖点描述。请突出产品的核心优势和独特功能，明确其与竞争产品的不同之处。描述应能引发目标用户的兴趣，强调产品如何为他们带来特定好处或解决问题。语言应具有吸引力，并能清晰传达产品的价值和使用场景，请用1.2.3.....段落形式输出方便用快速阅读，并加上适当的表情\'', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(28, 'system', 'ai_prompt_product_seo_description', '请为该商品生成一个优化的产品SEO描述。描述应包含主要关键词，概述产品的核心功能和优势，并吸引潜在客户点击。请确保描述简洁且具吸引力，能够清楚传达产品的价值主张，并符合搜索引擎的最佳实践。字数应控制在150-160个字符之间，以确保在搜索引擎结果页上完整显示。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(29, 'system', 'ai_prompt_product_seo_keywords', '请为该商品生成一个优化的产品SEO关键词。应包含主要关键词，概述产品的核心功能和优势，并吸引潜在客户点击。请确保描述简洁且具吸引力，能够清楚传达产品的价值主张，并符合搜索引擎的最佳实践。字数应控制在150-160个字符之间，以确保在搜索引擎结果页上完整显示。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(30, 'system', 'ai_prompt_product_seo_title', '请为该商品生成一个有效的产品SEO标题。标题应包含主要的关键词，以优化搜索引擎排名，并且吸引潜在客户的注意。请确保标题简洁且描述性强，突出产品的核心优势和独特之处，同时与用户的搜索意图紧密相关。标题字数应控制在60个字符以内，以便在搜索引擎结果页上完整显示。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(31, 'system', 'ai_prompt_product_slug', '请为该商品生成一个简洁、明确的产品slug。slug应简短且易于记忆，包含产品的主要关键词，以便于搜索引擎优化（SEO）和用户识别。请确保slug使用小写字母、连字符连接关键词，并避免使用特殊字符。slug应能够在简洁的同时准确传达产品名称或类型，使用户能够一目了然地理解产品的核心特征。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
(32, 'system', 'ai_prompt_product_summary', '请为该商品撰写一份简洁而引人注目的产品摘要。摘要应突出产品的核心功能、主要特点和独特卖点，根据目标用户，并且能够激发他们的购买欲望。请确保摘要语言简洁明了，同时能清楚地传达产品的价值和优势。输出为1-2句吸引用户的精炼内容。', 0, '2025-04-26 15:29:47', '2025-05-16 03:33:22'),
